#include <bits/stdc++.h>
using namespace std;
int mark[100005];
int bfs(int n,int k){
	if(n==k)return 0;
	queue<int> a;
	a.push(n);
	mark[n]=0;
	while(!a.empty()){
		int u=a.front();
		a.pop();
		if(u+1<100001 && u+1!=n && !mark[u+1]){
			mark[u+1]=mark[u]+1;
			if(u+1==k)return mark[k];
			a.push(u+1);
		}if(u-1>=0 && u-1!=n && !mark[u-1]){
			mark[u-1]=mark[u]+1;
			if(u-1==k)return mark[k];
			a.push(u-1);
		}if(u*2<100001 && u*2!=n && !mark[u*2]){
			mark[u*2]=mark[u]+1;
			if(u*2==k)return mark[k];
			a.push(u*2);
		}
	}
	return mark[k];
}
int main(){
	int n,k,t;
	cin>>t;
	while(t--){
	    memset(mark,0,sizeof(mark));
	    cin>>n>>k;
	    cout<<bfs(n,k)<<'\n';
	}
	return 0;
}
